import{_ as e,c as r,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"用户协议: 服务规则 | OpenCodeDocs","description":"了解 OpenCodeDocs 用户协议的服务使用规则、知识产权归属和免责条款，明确双方权利义务。","frontmatter":{"title":"用户协议: 服务规则 | OpenCodeDocs","sidebarTitle":"5 分钟了解规则","subtitle":"用户协议: 服务规则","description":"了解 OpenCodeDocs 用户协议的服务使用规则、知识产权归属和免责条款，明确双方权利义务。"},"headers":[],"relativePath":"zh/terms.md","filePath":"zh/terms.md"}'),o={name:"zh/terms.md"};function i(n,a,s,h,d,c){return l(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="用户服务协议" tabindex="-1">用户服务协议 <a class="header-anchor" href="#用户服务协议" aria-label="Permalink to &quot;用户服务协议&quot;">​</a></h1><p>最后更新日期：2026-01-01<br> 生效日期：2026-01-01</p><p>欢迎使用 OpenCodeDocs！在使用我们的服务之前，请仔细阅读本用户服务协议（以下简称&quot;本协议&quot;）。使用我们的服务即表示您同意接受本协议的约束。</p><h2 id="_1-服务说明" tabindex="-1">1. 服务说明 <a class="header-anchor" href="#_1-服务说明" aria-label="Permalink to &quot;1. 服务说明&quot;">​</a></h2><p>OpenCodeDocs 是一个专注于 AI 工具教程的开放平台，提供以下服务：</p><ul><li><strong>教程内容</strong>：开源 AI 工具（如 Claude Code、Cursor、LangChain 等）的使用教程</li><li><strong>代码验证</strong>：基于源码仓库自动验证教程中的代码可运行性</li><li><strong>社区功能</strong>：用户可通过 GitHub 参与内容贡献和讨论</li></ul><p>我们保留随时修改、暂停或终止部分或全部服务的权利，恕不另行通知。</p><h2 id="_2-账号注册与管理" tabindex="-1">2. 账号注册与管理 <a class="header-anchor" href="#_2-账号注册与管理" aria-label="Permalink to &quot;2. 账号注册与管理&quot;">​</a></h2><h3 id="注册条件" tabindex="-1">注册条件 <a class="header-anchor" href="#注册条件" aria-label="Permalink to &quot;注册条件&quot;">​</a></h3><ul><li>您必须年满 16 周岁（或在您所在地区达到法定年龄）</li><li>提供真实、准确的注册信息</li><li>每位用户仅可注册一个账号</li></ul><h3 id="账号安全" tabindex="-1">账号安全 <a class="header-anchor" href="#账号安全" aria-label="Permalink to &quot;账号安全&quot;">​</a></h3><ul><li>您有责任保管好账号凭证，不得与他人共享</li><li>如发现账号被盗用，请立即联系我们</li><li>因账号管理不善导致的损失，由您自行承担</li></ul><h3 id="账号注销" tabindex="-1">账号注销 <a class="header-anchor" href="#账号注销" aria-label="Permalink to &quot;账号注销&quot;">​</a></h3><p>您可以随时申请注销账号。注销后，您的个人数据将在 30 天内删除，但公开发布的内容可能仍会保留。</p><h2 id="_3-用户行为规范" tabindex="-1">3. 用户行为规范 <a class="header-anchor" href="#_3-用户行为规范" aria-label="Permalink to &quot;3. 用户行为规范&quot;">​</a></h2><p>在使用本平台时，您同意不从事以下行为：</p><ul><li>发布违法、有害、威胁、骚扰、诽谤或侵权的内容</li><li>冒充他人或虚假陈述身份</li><li>未经授权访问他人账号或系统</li><li>干扰或破坏服务的正常运行</li><li>使用自动化工具大规模抓取内容（合理的 API 使用除外）</li><li>将教程内容用于商业目的而不遵守许可协议</li></ul><h2 id="_4-知识产权" tabindex="-1">4. 知识产权 <a class="header-anchor" href="#_4-知识产权" aria-label="Permalink to &quot;4. 知识产权&quot;">​</a></h2><h3 id="开源许可说明" tabindex="-1">开源许可说明 <a class="header-anchor" href="#开源许可说明" aria-label="Permalink to &quot;开源许可说明&quot;">​</a></h3><ul><li><strong>教程内容</strong>：采用 <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a> 协议，允许非商业性分享和改编，但需署名并以相同方式共享</li><li><strong>网站构建</strong>：本项目基于 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> 构建，遵循 MIT 协议</li><li><strong>用户贡献</strong>：您提交的内容默认授权平台在遵守上述协议的前提下使用</li></ul><p>OpenCodeDocs 的商标、Logo 和其他品牌标识受法律保护，未经授权不得使用。</p><h2 id="_5-免责声明" tabindex="-1">5. 免责声明 <a class="header-anchor" href="#_5-免责声明" aria-label="Permalink to &quot;5. 免责声明&quot;">​</a></h2><ul><li><strong>服务中断</strong>：我们不保证服务不间断或无错误。因维护、升级或不可抗力导致的服务中断，我们不承担责任</li><li><strong>内容准确性</strong>：教程内容仅供参考，我们不保证其在所有环境下的可用性</li><li><strong>代码使用风险</strong>：您运行教程中的代码需自行承担风险，建议在隔离环境中测试</li><li><strong>第三方链接</strong>：本站可能包含指向第三方网站的链接，我们不对其内容负责</li></ul><h2 id="_6-协议修改" tabindex="-1">6. 协议修改 <a class="header-anchor" href="#_6-协议修改" aria-label="Permalink to &quot;6. 协议修改&quot;">​</a></h2><p>我们可能会不时修改本协议。修改后的协议将在网站上公布，并通过以下方式通知您：</p><ul><li>在网站显著位置公告</li><li>通过注册邮箱发送通知（如适用）</li></ul><p>继续使用我们的服务即表示您接受修改后的协议。如您不同意修改，请停止使用服务。</p><h2 id="_7-争议解决" tabindex="-1">7. 争议解决 <a class="header-anchor" href="#_7-争议解决" aria-label="Permalink to &quot;7. 争议解决&quot;">​</a></h2><ul><li><strong>适用法律</strong>：本协议受中华人民共和国法律管辖</li><li><strong>争议解决</strong>：双方应友好协商解决争议；协商不成的，任何一方可向被告所在地有管辖权的人民法院提起诉讼</li></ul><h2 id="_8-联系方式" tabindex="-1">8. 联系方式 <a class="header-anchor" href="#_8-联系方式" aria-label="Permalink to &quot;8. 联系方式&quot;">​</a></h2><p>如您对本协议有任何疑问，请联系：</p><ul><li><strong>邮箱</strong>：<a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const g=e(o,[["render",i]]);export{p as __pageData,g as default};
